// NORMALIZE INPUT -- Unified Message Format
// Merges Signal messages and webhook payloads into one shape.
// Signal poll returns: {data: "[{envelope:{...}}]"} -- data is a JSON STRING
// IMPORTANT: Skips typing indicators, read receipts, and other non-message envelopes.
// Output: {_source, _sender, _senderUuid, _message, _timestamp, _hasAttachment, _attachmentType, _pipeline_start_ms}

const items = $input.all();
const results = [];

for (const item of items) {
  let json = item.json;

  // ---- SIGNAL POLL FORMAT ----
  // Poll Signal API returns {data: "[{...}]"} where data is a string
  if (typeof json.data === 'string' && json.data.startsWith('[')) {
    try {
      const messages = JSON.parse(json.data);
      for (const msg of messages) {
        if (!msg.envelope) continue;
        const env = msg.envelope;
        const dm = env.dataMessage;

        // Skip non-message envelopes: typing indicators, receipts, etc.
        // Only process envelopes that have a dataMessage with actual content
        if (!dm) continue;
        if (!dm.message && !(dm.attachments && dm.attachments.length > 0)) continue;

        const sender = env.sourceNumber || env.sourceName || '';
        const senderUuid = env.sourceUuid || '';
        const message = dm.message || '';
        const timestamp = dm.timestamp || env.timestamp || Date.now();
        let hasAttachment = false;
        let attachmentType = '';
        let attachmentId = '';
        if (dm.attachments && dm.attachments.length > 0) {
          hasAttachment = true;
          attachmentType = dm.attachments[0].contentType || '';
          attachmentId = dm.attachments[0].id || '';
        }
        results.push({
          json: {
            _source: 'signal',
            _sender: sender,
            _senderUuid: senderUuid,
            _message: message.trim(),
            _timestamp: timestamp,
            _hasAttachment: hasAttachment,
            _attachmentType: attachmentType,
            _attachmentId: attachmentId,
            _pipeline_start_ms: Date.now()
          }
        });
      }
    } catch (e) {
      // JSON parse failed -- skip
    }
    continue;
  }

  // ---- SIGNAL DIRECT FORMAT ----
  if (json.envelope) {
    const dm = json.envelope.dataMessage;
    if (!dm) continue; // skip typing indicators, receipts
    if (!dm.message && !(dm.attachments && dm.attachments.length > 0)) continue;
    const message = dm.message || '';
    const sender = json.envelope.sourceNumber || json.envelope.sourceName || '';
    const senderUuid = json.envelope.sourceUuid || '';
    const timestamp = dm.timestamp || json.envelope.timestamp || Date.now();
    let hasAttachment = false;
    let attachmentType = '';
    let attachmentId = '';
    if (dm.attachments && dm.attachments.length > 0) {
      hasAttachment = true;
      attachmentType = dm.attachments[0].contentType || '';
      attachmentId = dm.attachments[0].id || '';
    }
    results.push({
      json: {
        _source: 'signal',
        _sender: sender,
        _senderUuid: senderUuid,
        _message: message.trim(),
        _timestamp: timestamp,
        _hasAttachment: hasAttachment,
        _attachmentType: attachmentType,
        _attachmentId: attachmentId,
        _pipeline_start_ms: Date.now()
      }
    });
    continue;
  }

  // ---- WEBHOOK FORMAT ----
  if (json.body) {
    const source = json.body.source || 'webhook';
    let message = json.body.url || json.body.message || json.body.text || '';
    if (json.body.flags) message = json.body.flags + ' ' + message;
    const sender = json.body.sender || 'webhook';
    const senderUuid = json.body.senderUuid || json.body.sender_uuid || 'YOUR_UUID';
    results.push({
      json: {
        _source: source,
        _sender: sender,
        _senderUuid: senderUuid,
        _message: message.trim(),
        _timestamp: Date.now(),
        _hasAttachment: false,
        _attachmentType: '',
        _attachmentId: '',
        _pipeline_start_ms: Date.now()
      }
    });
    continue;
  }

  // ---- DIRECT PARAMS ----
  if (json.url || json.message) {
    let message = json.url || json.message || json.text || '';
    if (json.flags) message = json.flags + ' ' + message;
    const directUuid = json.senderUuid || json.sender_uuid || 'YOUR_UUID';
    results.push({
      json: {
        _source: json.source || 'webhook',
        _sender: 'webhook',
        _senderUuid: directUuid,
        _message: message.trim(),
        _timestamp: Date.now(),
        _hasAttachment: false,
        _attachmentType: '',
        _attachmentId: '',
        _pipeline_start_ms: Date.now()
      }
    });
  }
}

return results;

// COMMAND PARSER -- Extract flags + URL from message
// All Phase 2 flags are parsed but currently no-op.

const item = $input.first().json;
const message = item._message || '';

const flags = {
  tts: false, translate: null, deep: false,
  quick: false, transcript_only: false,
  braindump: false, book: false, help: false, dub: null
};

let content = message;

if (/\bhelp\b/i.test(content)) { flags.help = true; }
if (/\btts\b/i.test(content)) { flags.tts = true; content = content.replace(/\btts\b/i, ''); }
if (/\btranslate\s+(en|fr|nl|de|es)\b/i.test(content)) {
  flags.translate = content.match(/translate\s+(en|fr|nl|de|es)/i)[1];
  content = content.replace(/\btranslate\s+(en|fr|nl|de|es)\b/i, '');
}
if (/\bdub\s+(en|fr|nl|de|es)\b/i.test(content)) {
  flags.dub = content.match(/dub\s+(en|fr|nl|de|es)/i)[1];
  content = content.replace(/\bdub\s+(en|fr|nl|de|es)\b/i, '');
}
if (/\bdeep\b/i.test(content)) { flags.deep = true; content = content.replace(/\bdeep\b/i, ''); }
if (/\bquick\b/i.test(content)) { flags.quick = true; content = content.replace(/\bquick\b/i, ''); }
if (/\btranscript\b/i.test(content)) { flags.transcript_only = true; content = content.replace(/\btranscript\b/i, ''); }
if (/\bbraindump\b/i.test(content)) { flags.braindump = true; content = content.replace(/\bbraindump\b/i, ''); }
if (/\bbook\b/i.test(content)) { flags.book = true; content = content.replace(/\bbook\b/i, ''); }

const url = content.trim().match(/https?:\/\/\S+/)?.[0] || null;
const text = url ? content.replace(url, '').trim() : content.trim();

return [{ json: { ...item, _flags: flags, _url: url, _text: text, _hasAttachment: item._hasAttachment || false } }];

// HELP RESPONSE — Returns command list with Unicode bold headers

// Unicode Bold converter (Mathematical Bold Sans-Serif)
function toBold(text) {
  const boldMap = {};
  for (let i = 0; i < 26; i++) {
    boldMap[String.fromCharCode(65 + i)] = String.fromCodePoint(0x1D5D4 + i);
  }
  for (let i = 0; i < 26; i++) {
    boldMap[String.fromCharCode(97 + i)] = String.fromCodePoint(0x1D5EE + i);
  }
  for (let i = 0; i < 10; i++) {
    boldMap[String.fromCharCode(48 + i)] = String.fromCodePoint(0x1D7EC + i);
  }
  return text.split('').map(c => boldMap[c] || c).join('');
}

const helpText = [
  toBold('Welcome to STMNA Signal!'),
  '',
  'Send any YouTube, web page, link to PDF or post on X and get summarized content back!',
  '',
  'Jobs are processed at night and results will be shared with you next day at 08:00AM.',
  '',
  toBold('Bot Commands:'),
  '',
  '(no flag) - Full summary + vault save',
  'quick - Fast summary, Signal only (no vault)',
  'deep - Extended detailed analysis',
  'help - This command list',
  '',
  toBold('Coming soon:'),
  '',
  'transcript - Transcription only',
  'braindump - Structure text to vault',
  'tts - Audio version of summary',
  'translate [lang] - Translate summary',
  'dub [lang] - Dubbed video',
  '',
  toBold('Examples:'),
  'https://youtube.com/watch?v=abc',
  'quick https://article.com/post',
  'deep https://github.com/user/repo'
].join('\n');

return [{ json: { ...$input.first().json, _response: helpText, _skipVault: true } }];

// NORMALIZE CONTENT KEY
// Extracts a stable, cache-friendly key from the URL.
// YouTube: video ID (11 chars). Web: cleaned URL without tracking params.
// Also determines _contentType for downstream routing.
// UPDATED: Phase 1D — Added X/Twitter, GitHub, PDF, Spotify, Tidal detection
//          + braindump/voice-note detection for no-URL messages

const item = $('Command Parser').first().json;
const url = item._url || '';

// Attach identity from the Resolve Identity node
const identityData = $('Resolve Identity').first().json;
const userId = identityData?.id || null;
const userRole = identityData?.role || 'user';
const userName = identityData?.name || 'Unknown';

let contentKey = '';
let contentType = '';

if (!url) {
  // No URL — check for voice note attachment or braindump text
  const isVoiceNote = item._hasAttachment && (item._attachmentType || '').startsWith('audio/');
  const isBraindump = (item._flags?.braindump === true) || (!isVoiceNote && item._text && item._text.length > 0);

  return [{ json: {
    ...item,
    _userId: userId,
    _userRole: userRole,
    _userName: userName,
    _contentKey: '',
    _contentType: isVoiceNote ? 'voice-note' : (isBraindump ? 'braindump' : 'none')
  }}];
}

// ---- YOUTUBE ----
const ytPatterns = [
  /(?:youtube\.com\/watch\?.*v=)([a-zA-Z0-9_-]{11})/,
  /(?:youtu\.be\/)([a-zA-Z0-9_-]{11})/,
  /(?:youtube\.com\/shorts\/)([a-zA-Z0-9_-]{11})/,
  /(?:youtube\.com\/live\/)([a-zA-Z0-9_-]{11})/,
  /(?:youtube\.com\/embed\/)([a-zA-Z0-9_-]{11})/
];
for (const pattern of ytPatterns) {
  const match = url.match(pattern);
  if (match) {
    contentKey = `yt:${match[1]}`;
    contentType = 'youtube';
    break;
  }
}

// ---- X/TWITTER ----
if (!contentType && /^https?:\/\/(www\.)?(x\.com|twitter\.com)\//i.test(url)) {
  contentType = 'x-post';
}

// ---- GITHUB/GITLAB ----
if (!contentType && /^https?:\/\/(www\.)?(github\.com|gitlab\.com)\//i.test(url)) {
  contentType = 'github';
}

// ---- PDF (URL ending in .pdf) ----
if (!contentType && /\.pdf(\?|#|$)/i.test(url)) {
  contentType = 'paper';
}

// ---- SPOTIFY ----
if (!contentType && /^https?:\/\/open\.spotify\.com\//i.test(url)) {
  contentType = 'spotify';
}

// ---- TIDAL ----
if (!contentType && /^https?:\/\/(www\.)?tidal\.com\//i.test(url)) {
  contentType = 'tidal';
}

// ---- WEB (fallback) ----
if (!contentType) {
  contentType = 'web';
}

// Build content key for all URL-based types (except YouTube, already set above)
if (!contentKey) {
  try {
    const parsed = new URL(url);
    const trackingParams = [
      'utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content',
      'fbclid', 'gclid', 'ref', 'ref_src', 'ref_url',
      'mc_cid', 'mc_eid', 's', 'si'
    ];
    for (const param of trackingParams) {
      parsed.searchParams.delete(param);
    }
    const hostPath = parsed.hostname.toLowerCase() + parsed.pathname.replace(/\/$/, '');
    const query = parsed.searchParams.toString() ? '?' + parsed.searchParams.toString() : '';
    const hash = parsed.hash || '';
    contentKey = `web:${hostPath}${query}${hash}`;
  } catch (e) {
    contentKey = `web:${url.replace(/^https?:\/\//, '').replace(/\/$/, '')}`;
  }
}

return [{ json: {
  ...item,
  _userId: userId,
  _userRole: userRole,
  _userName: userName,
  _contentKey: contentKey,
  _contentType: contentType
}}];

// CHECK CACHE HIT — Routes based on Cache Check PostgreSQL result
// The Cache Check node returns the cached row if found, empty object if not.
// We check if content_key exists and is non-empty.
const cacheResult = $input.first().json;
const hasCacheHit = !!(cacheResult && cacheResult.content_key && cacheResult.content_key.length > 0);

return [{ json: { ...cacheResult, _hasCacheHit: hasCacheHit } }];

// SERVE CACHED RESULT
// Formats the cached summary for Signal delivery.
// Admin gets truncated summary + Forgejo link.
// Regular user gets full summary text.

const item = $('Normalize Content Key').first().json;
const cacheData = $('Cache Check').first().json;
const userRole = item._userRole || 'user';
const summary = cacheData._cachedSummary || 'No summary available.';
const vaultPath = cacheData.vault_path || '';
const title = cacheData.title || 'Untitled';
const sourceUrl = cacheData.source_url || item._url || '';

// Admin UUID for comparison
const ADMIN_UUID = 'YOUR_UUID';
const isAdmin = (item._senderUuid === ADMIN_UUID || userRole === 'admin');

let response = '';

if (isAdmin) {
  // Admin: truncated summary (~1800 chars) + Forgejo vault link
  const MAX_LEN = 1800;
  const truncated = summary.length > MAX_LEN
    ? summary.substring(0, MAX_LEN) + '\n\n[... truncated]'
    : summary;

  response = `\u2705 [CACHED] ${title}\n\n${truncated}`;

  if (vaultPath) {
    const forgejoBase = 'https://YOUR_FORGEJO_DOMAIN/STMNA/second-brain/src/branch/main/';
    response += `\n\n\ud83d\udcc1 Vault: ${forgejoBase}${encodeURI(vaultPath)}`;
  }

  if (sourceUrl) {
    response += `\n\n\ud83d\udd17 Source: ${sourceUrl}`;
  }
} else {
  // Regular user: full summary
  response = `\u2705 ${title}\n\n${summary}`;

  if (sourceUrl) {
    response += `\n\n\ud83d\udd17 Source: ${sourceUrl}`;
  }
}

// Check if admin and no vault_path -- queue a vault write job
let needsVaultWrite = false;
if (isAdmin && !vaultPath) {
  needsVaultWrite = true;
}

return [{ json: {
  ...item,
  _response: response,
  _cached: true,
  _needsVaultWrite: needsVaultWrite,
  _cachedTitle: title,
  _cachedSummary: summary
}}];

