// SEND ACK — Acknowledges queued job to sender
// Admin: "Getting details on [link]"
// User: "Getting details on [link] + ready tomorrow morning"

const item = $('Normalize Content Key').first().json;
const ADMIN_UUID = 'YOUR_UUID';
const isAdmin = (item._senderUuid === ADMIN_UUID || item._userRole === 'admin');
const url = item._url || '';

let response = '';

if (isAdmin) {
  response = `\ud83d\udd0d Getting details on ${url}`;
} else {
  response = `\ud83d\udd0d Getting details on ${url}\n\nReady for you tomorrow first thing in the morning!`;
}

return [{ json: { ...item, _response: response } }];

// ERROR HANDLER -- Formats user-friendly error messages
const item = $input.first().json;
const errorMsg = item.error?.message || item.message || 'Unknown error occurred';
const nodeName = item.error?.node || 'Unknown node';

// Build user-friendly error message
const response = [
  'Error processing your content:',
  '',
  errorMsg.substring(0, 500),
  '',
  `Failed at: ${nodeName}`,
  '',
  'Tips:',
  '- Check if the URL is accessible',
  '- YouTube: verify video is not private/age-restricted',
  '- Web: some sites block scraping',
  '- Try again in a few minutes',
].join('\n');

return [{ json: { ...(item._senderUuid ? item : {}), _response: response, _error: true, _senderUuid: item._senderUuid || 'YOUR_UUID' } }];

// UNSUPPORTED RESPONSE — Spotify/Tidal "coming soon" + empty message handling
const item = $input.first().json;
const ct = item._contentType || 'none';

let response = '';
if (ct === 'spotify') {
  response = '\u{1F3B5} Spotify support coming soon! For now, share the YouTube link if available.';
} else if (ct === 'tidal') {
  response = '\u{1F3B5} Tidal support coming soon! For now, share the YouTube link if available.';
} else {
  // _contentType === 'none' — no URL, no text, no attachment
  response = "I didn't catch that. Send me a URL, a voice note, or text with the braindump flag.\n\nSend help for available commands.";
}

return [{ json: { ...item, _response: response } }];

